effect.script:
function animate(env,el,p) {
    if( env.editMode=="eyedropper-drag" && env.selected ) {
        el.shaderGroups = [1];
    } else {
        el.shaderGroups = [0];
    }
    return el;
}

effect.shader:
void main() {

    highp mat3 rgb2yuv = mat3(
         0.299,     0.587,    0.114,
        -0.14713,  -0.28886,  0.436,
         0.615,    -0.51499, -0.10001
    );

    highp mat3 yuv2rgb = mat3(
        1.0,  0.0,      1.13983,
        1.0, -0.39465, -0.58060,
        1.0,  2.03211,  0.0
    );

    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec3 srcColor = texColor.rgb / texColor.a;
    vec3 oldColorYUV = oldcolor.rgb * rgb2yuv;
    vec3 srcColorYUV = srcColor * rgb2yuv;
    vec3 diffYUV = abs(oldColorYUV - srcColorYUV);
    diffYUV.yz *= 4.0;
    diffYUV.x *= 0.5;
    float diff = length(diffYUV);
    float b = max(threshold-max(feather,0.0005),0.);
    float a = min(threshold+max(feather,0.0005),4.);
    float p = smoothstep( a, min(b,a-0.0005), diff);
    vec3 newColorAdjRGB = newcolor.rgb/newcolor.a;
    if(lockLuminance) {
        vec3 newColorAdjYUV = newColorAdjRGB * rgb2yuv;
        newColorAdjYUV.x = srcColorYUV.x;
        newColorAdjRGB = newColorAdjYUV * yuv2rgb;
    } else {
        newColorAdjRGB = srcColor-(oldcolor.rgb/oldcolor.a)+newColorAdjRGB;
    }
    gl_FragColor = mix(texColor,vec4(mix(srcColor,newColorAdjRGB,p),1.0)*texColor.a,newcolor.a*alpha);

}
